function getMultiplier(region) {
  const m = { northeast: 1.35, west: 1.30, midwest: 0.92, south: 0.88, southeast: 0.90, mountain: 1.02 };
  return m[region] || 1.0;
}

function fmtDollar(n) { return "$" + n.toLocaleString(); }

